questions = []
# У нас ровно 100 фактов. Чтобы получить 300 вопросов, мы прогоним каждый факт через 3 разных шаблона.

for fact in facts:
    term, right_ans, w1, w2, w3 = fact
    
    opts1 = [cap(right_ans), cap(w1), cap(w2), cap(w3)]
    random.shuffle(opts1)
    q1 = {
        "q": f"Что из нижеперечисленного является верным определением понятия «{term}»?",
        "o": opts1,
        "a": opts1.index(cap(right_ans))
    }
    questions.append(q1)
    
    opts2 = [cap(term), cap("Экологический мониторинг"), cap("Опасная производственная ситуация"), cap("Система контроля качества")]
    # Подмешиваем случайные термины из других фактов для правдоподобности
    other_terms = random.sample([f[0] for f in facts if f[0] != term], 3)
    opts2 = [cap(term)] + [cap(t) for t in other_terms]
    random.shuffle(opts2)
    q2 = {
        "q": f"Каким термином (понятием) правильно описывается следующее: {right_ans.lower()}?",
        "o": opts2,
        "a": opts2.index(cap(term))
    }
    questions.append(q2)
    
    opts3 = [cap(right_ans), cap(w1), cap(w2), cap(w3)]
    random.shuffle(opts3)
    q3 = {
        "q": f"Выберите наиболее точное утверждение. {term} — это:",
        "o": opts3,
        "a": opts3.index(cap(right_ans))
    }
    questions.append(q3)

random.shuffle(questions)

for i, q in enumerate(questions):
    html_template += f'        {{ q: "{i+1}. {q["q"]}", o: {json.dumps(q["o"], ensure_ascii=False)}, a: {q["a"]} }},\n'

html_template += """
    ];

const quizContainer = document.getElementById('quiz-container');
let score = 0;

quizData.forEach((item, index) => {
    const qDiv = document.createElement('div');
    qDiv.className = 'question-container';
    qDiv.dataset.answered = 'false';
    qDiv.dataset.correct = item.a;
    
    let optionsHtml = '';
    item.o.forEach((opt, idx) => {
        optionsHtml += `
            <label class="option-label">
                <input type="radio" name="q${index}" value="${idx}" onchange="checkAnswer(this, this.parentElement.parentElement.parentElement)">
                <div class="custom-radio"></div>
                <span class="option-text">${opt}</span>
            </label>
        `;
    });
    
    qDiv.innerHTML = `<div class="question-text">${item.q}</div><div class="options">${optionsHtml}</div>`;
    quizContainer.appendChild(qDiv);
});

function checkAnswer(radio, qDiv) {
    if (qDiv.dataset.answered === 'true') return;
    qDiv.dataset.answered = 'true';
    
    const correctAns = parseInt(qDiv.dataset.correct);
    const selectedVal = parseInt(radio.value);
    
    qDiv.querySelectorAll('input').forEach(i => { i.disabled = true; i.parentElement.style.pointerEvents = 'none'; });
    
    if (selectedVal === correctAns) {
        score++;
        radio.parentElement.classList.add('correct');
    } else {
        radio.parentElement.classList.add('incorrect');
        qDiv.querySelector(`input[value="${correctAns}"]`).parentElement.classList.add('correct');
    }
    
    const answered = document.querySelectorAll('.question-container[data-answered="true"]').length;
    document.getElementById('progressBar').style.width = (answered / quizData.length * 100) + '%';
    
    if (answered === quizData.length) {
        document.getElementById('scoreVal').innerText = score + ' из ' + quizData.length;
        document.getElementById('result-card').style.display = 'block';
    }
}
</script>
</body>
</html>
"""

with io.open(r"d:\codes\подготовка\ohrana_test.html", "w", encoding="utf-8") as f:
    f.write(html_template)

print("HTML файл с идеальными тестами (ровно 300 вопросов) успешно создан!")
